SELECT c.country_name, l.logistics_index
FROM countries c
JOIN logistics l ON c.country_id = l.country_id;

SELECT airport_totals
FROM logistics
WHERE country_id = 1;

SELECT available_manpower 
FROM manpower 
WHERE country_id = 1;

SELECT government_type, geographic_region
FROM countries
WHERE cluster = (SELECT cluster FROM countries WHERE country_id = 1);

SELECT AVG(total_population) AS average_anchor_weight
FROM manpower
WHERE military_service_voluntary = 0;

SELECT COUNT(*)
FROM financials
WHERE defense_spending_per_capita < (
    SELECT AVG(defense_spending_per_capita)
    FROM financials
);

SELECT country_id
FROM manpower
WHERE available_manpower = (SELECT MAX(available_manpower) FROM manpower);
